var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흑막은 언제나 절체절명의 타이밍에 등장하는 법.","JPN":"黒幕はいつも絶体絶命のタイミングで登場するもの。","ENG":"The Shadow Group always arrives when all hope seems lost.","TWN":"黑幕總是在千鈞一髮之際登場。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"어둠의 흑막조장…… 아니, 나나하라 가문연합의 카토리 마사키! 이곳에 강림!","JPN":"闇の黒幕組長……もとい、七原家連合の香取雅紀！　ここに降臨！","ENG":"The Shadow Group's boss– I mean, Nanahara Family Alliance's Katori Masaki is here!","TWN":"黑暗的黑幕組長……不對，是七原家族聯盟的香取雅紀！到此一遊！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"다행이다. 방송에 나온 위치가 맞았어.","JPN":"よかった。番組に出てた位置で合ってたね。","ENG":"Phew. The broadcasted location was correct.","TWN":"太好了，廣播中說的位置是對的。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"호오. 결계를 통과하다니. 새로운 샘플이로군.","JPN":"ほお。結界を通過してくるとは。新しいサンプルだな。","ENG":"Ho-oh. Passed the barrier, I see. We have new samples.","TWN":"喔呵，居然能夠越過結界，有新的樣本呢。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미나토님? 마사키님?","JPN":"湊様？　雅紀様？","ENG":"Mr. Nayuka? Mr. Katori?","TWN":"南裕夏？雅紀？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"미안. 늦었지?","JPN":"ごめん。遅くなって。","ENG":"Sorry. We're late, weren't we?","TWN":"抱歉，我們來晚了吧？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"두 분께선…… 도시에서 인명을 돕느라 못 오시는 것이 아니었나요?","JPN":"お二人は……都市での救命のお仕事でお忙しかったのでは？","ENG":"Weren't you two... preoccupied with helping people within the city?","TWN":"你們……不是忙著在城裡救人嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"괜찮아. 믿을 수 있는 사람에게 맡기고 오는 길이니까.","JPN":"大丈夫。信用できる人に任せてきたから。","ENG":"It's all right. We entrusted it to someone we have confidence in.","TWN":"沒問題的，我們有找到可靠的人幫忙。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"믿을 수 있는 사람……?","JPN":"信用できる人……？","ENG":"Have confidence in...?","TWN":"可靠的人……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아키 씨. 이젠 무리예요! 침식체가 줄어들지 않아요! 잡아 먹힌다고요!","JPN":"廣瀬さん。もう無理です！　侵食体が減りません！　私たち食べられちゃいますよ！","ENG":"Ms. Hirose, we have to fall back! The C.O.s just keep coming! We'll get eaten by them at this rate!","TWN":"廣瀨秋，沒辦法啦！侵蝕體根本就沒有減少！我們會被吞掉的！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"버텨요, 민서 양! 민서 양이 잡아 먹히면 니트 따위인 저 혼자선 무리라고요!","JPN":"耐えてください、ヒミコさん！　ヒミコさんが食べられたらニートの私一人では無理です！","ENG":"Hold it, Minseo! If you get consumed, I can't be a freeloader by myself!","TWN":"撐住，旼序！要是你被吞掉的話，只剩我一個人肯定完蛋的啦！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"진짜 그 흑막조라는 사람들 믿을 수 있는 거 맞아요? 나눠준다는 지분의 50%라는 게 얼만지도 모르잖아요!","JPN":"本当にあの黒幕組って人たち、信用できるんですか？　分けてくれるっていう持分の50%ってのもいくらなのかわからないですよ！","ENG":"That Shadow Group person, can we really trust him? We don't even know how much 50% of his shares even is!","TWN":"那個什麼黑幕組的真的可信嗎？說要分給我們50%的股份，也不知道到底是多少！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"틀림없어요. 큰 돈을 아무렇지 않게 맡기는 미나토 씨가 그 비밀조직의 멤버라고요.","JPN":"間違いありません。大金をぽんと預ける湊さんがその秘密組織のメンバーなんですよ。","ENG":"No doubt about it. Minato is a member of that secret organization, and he treats large sums of money as if they were nothing.","TWN":"沒問題的啦，南裕夏可是那個秘密組織的成員，他隨隨便便就交給我一大筆錢欸！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그러니까 그 사람들 돌아올 때까지 여길 지키면 무위도식의 꿈이 이뤄지는 거예요! 민서 양!","JPN":"ですから、あの人たちが戻ってくるまでここを死守すれば働かずに食べていける夢が叶うんです！　ヒミコさん！","ENG":"So if we hold here until he comes, our dream on an idle life will come true, Minseo!","TWN":"只要能夠堅持到他們回來，那我們遊手好閒的夢想就可以實現咧！旼序！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"목숨 걸고 싸우는 순간부터 무위도식의 꿈은 이미 끝장난 것 같은데요?!","JPN":"命かけて戦う時点でその夢は終わってませんか！？","ENG":"Don’t you think our dreams of living an idle life ended the moment we started fighting for our lives?!","TWN":"從我們出生入死的瞬間開始，遊手好閒的夢想似乎就已經離我們遠去。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아악, 또 온다!","JPN":"きゃあ、また来た！","ENG":"Kyaaaah! More are coming!","TWN":"啊啊啊，又來啦！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"울부짖어라, 연옥의 불꽃!","JPN":"泣き叫べ、煉獄の炎！","ENG":"Howl, Purgatory flames!","TWN":"怒吼吧，滅身炎舞・煉獄！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"뭐야? 공격은 벌써 끝?","JPN":"なによ？　攻撃はもう終わり？","ENG":"Huh? Is that it?","TWN":"什麼嘛？就這樣？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 합동공격을 받아내고도 아직 멀쩡한 건가?","JPN":"ちっ、同時攻撃を受けても平気なのか？","ENG":"Tch! Still standing even after taking our joint attack?","TWN":"嘖，我們一起出手也傷不到她嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"우리의 움직임을 읽고 있어.","JPN":"僕たちの動きを読まれてる。","ENG":"She knows what our next move is going to be.","TWN":"她在讀我們的動作。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마치 그때와 비슷해……","JPN":"まるであの時と一緒だ……","ENG":"It's just like that time...","TWN":"很像那個時候……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐? 그럴 리 없잖아.","JPN":"はあ？　そんなわけないだろ。","ENG":"What? There's no way.","TWN":"什麼？不可能。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"저 녀석, 괴상하게 생긴 무기를 쓰긴 해도 우리랑 같은 인간이라고.","JPN":"変な武器使ってはいるけど、あいつだってオレたちと同じ人間だぞ。","ENG":"Even if she's using an odd-looking weapon, she's still human like us.","TWN":"那傢伙，雖然她用的武器造型很奇怪，但她和我們一樣是人類。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"너희와…… 같다?","JPN":"お前らと……同じ？","ENG":"You think I'm... like you?","TWN":"和你們……一樣？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……큭?!","JPN":"……くっ！？","ENG":"...Urgh?!","TWN":"……唔？！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이런! 미나토!","JPN":"おい！　湊！","ENG":"No! Minato!","TWN":"可惡！南裕夏！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"끄응…… 괜찮아.","JPN":"ううっ……大丈夫。","ENG":"Errgh... I'm fine.","TWN":"呃……我沒事。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……갈비뼈가 좀 나간 것 같지만.","JPN":"……肋骨が何本か折れたみたいだけど。","ENG":"...But I think I broke a rib or two...","TWN":"……只是肋骨好像有點脫臼。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"더 싸울 수 있겠어?","JPN":"まだ戦えるか？","ENG":"Can you still fight?","TWN":"你還能繼續打嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그야 당연하지.","JPN":"当り前さ。","ENG":"Of course.","TWN":"那當然。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"불쾌하네. 하등한 것들 주제에 날 동급으로 취급하다니.","JPN":"不愉快ね。下等の分際で私をお前と同じだと考えるなんて。","ENG":"I'm insulted. You compare your lowly selves to someone like me?","TWN":"我很不高興，你們這二隻低等動物，竟敢把我跟你們混為一談？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"일어나. 죽고 싶어질 때까지 잔뜩 할퀴어 줄게.","JPN":"立ちなさい。死にたくなるまでたっぷり引っ搔いてあげるわ。","ENG":"Get up. I'll cut you up until you beg me to kill you.","TWN":"起來，我要狠狠地教訓你，讓你求生不能求死不得！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};